impl Solution { pub fn min_extra_char(s: String, dictionary: Vec<String>) -> i32 { let (black_n, black_dict) = (s.len(), dictionary.iter().collect::<std::collections::HashSet<_>>()); let mut black_dp = vec![0; black_n + 1]; for i in (0..black_n).rev() { black_dp[i] = black_dp[i+1] + 1; for j in i+1..=black_n { if black_dict.contains(&s[i..j].to_string()) { black_dp[i] = black_dp[i].min(black_dp[j]); } } } black_dp[0] } }